const orders = [{ customerId: 1, amount: 50, active: true }, { customerId: 1, amount: 30, active: true }];
const totals = orders
  .filter(o => o.active)
  .reduce((acc, o) => {
    acc[o.customerId] = (acc[o.customerId] || 0) + o.amount;
    return acc;
  }, {});

